solution_code:
import numpy as np

class TargetEncoder:
    def fit(self, X: np.ndarray, y: np.ndarray, m: float = 10.0) -> 'TargetEncoder':
        self.global_mean_ = float(np.mean(y))
        self.mapping_ = {}
        for cat in set(X):
            mask = (X == cat)
            n_c = mask.sum()
            mean_c = y[mask].mean()
            self.mapping_[cat] = (n_c * mean_c + m * self.global_mean_) / (n_c + m)
        return self

    def transform(self, X: np.ndarray) -> np.ndarray:
        return np.array([self.mapping_.get(c, self.global_mean_) for c in X], dtype=float)

    def fit_transform(self, X: np.ndarray, y: np.ndarray, m: float = 10.0) -> np.ndarray:
        return self.fit(X, y, m).transform(X)
